// =====================================================
// ⚙️  CONFIGURACIÓN — solo toca esta sección
// =====================================================
const SHOP_EMAIL  = 'urkosan098@gmail.com'; // email del dueño del taller
const SHOP_NAME   = 'RaceLab Performance';

// =====================================================
// EXTRACCIÓN DE DATOS
// Compatible con JSON plano (nuestra landing)
// y con Tally/formularios con data.fields
// =====================================================
const body   = $json.body   || $json        || {};
const fields = body?.data?.fields;

const getField          = (label) => (fields || []).find(f => (f.label || '').toLowerCase().includes(label.toLowerCase()));
const getText           = (label) => getField(label)?.value ?? null;
const getDropdownText   = (field) => { if (!field?.value?.length) return null; const s = (field.options || []).find(o => o.id === field.value[0]); return s?.text || null; };
const getCheckboxValues = (field) => {
  if (!field) return [];
  if (Array.isArray(field.value)) return (field.options || []).filter(o => field.value.includes(o.id)).map(o => o.text);
  if (field.value === true) { const m = (field.label || '').match(/\((.*?)\)/); return m ? [m[1]] : []; }
  return [];
};

let nombre, email, telefono, instagram, vehiculo, servicio, mensaje, taller, pais;

if (Array.isArray(fields)) {
  nombre    = getText('Nombre completo');
  telefono  = getText('Numero de telefono');
  instagram = getText('Instagram');
  vehiculo  = getText('Que coche tienes');
  pais      = getText('De donde eres');
  mensaje   = getText('importante');
  email     = getText('Email') || getText('Correo') || '';
  servicio  = getCheckboxValues(getField('Que te gustaria hacer')).join(', ');
  taller    = '';
} else {
  nombre    = body.name     || 'Cliente';
  email     = body.email    || '';
  telefono  = body.phone    || '';
  instagram = body.instagram|| '';
  vehiculo  = body.vehicle  || '—';
  servicio  = body.service  || 'Consulta';
  mensaje   = body.detail   || body.message || '';
  taller    = body.shop     || '';
  pais      = body.pais     || body.location|| '';
}

// =====================================================
// SCORE 0–100
// =====================================================
let score = 0;

// 🔧 SERVICIO (max 35)
const hotSvc = ['Swap', 'Electrónica', 'Competición', 'Stage 2'];
const midSvc = ['Preparación', 'Escape', 'Reprogramación', 'Stage 1', 'Downpipe'];
if      (hotSvc.some(s => servicio.includes(s))) score += 35;
else if (midSvc.some(s => servicio.includes(s))) score += 20;
else                                              score +=  8;

// 📱 TELÉFONO VÁLIDO (max 20)
const digits = (telefono || '').replace(/\D/g, '');
score += digits.length >= 9 ? 20 : 5;

// ⏱️ URGENCIA EN EL MENSAJE (max 25)
const msg          = (mensaje || '').toLowerCase();
const urgentWords  = ['presupuesto', 'precio', 'cuanto', 'cuánto', 'fecha', 'urgente', 'esta semana', 'este mes'];
score += urgentWords.some(w => msg.includes(w)) ? 25 : 10;

// 🧠 CLARIDAD / LONGITUD DEL MENSAJE (max 20)
const wordCount = msg.split(/\s+/).filter(Boolean).length;
if      (wordCount > 15) score += 20;
else if (wordCount >=  5) score += 12;
else                      score +=  4;

const finalScore = Math.min(100, Math.round(score));

// =====================================================
// TEMPERATURA
// =====================================================
let temperatura, prioridad, emoji;
if (finalScore >= 70) {
  temperatura = 'CALIENTE';
  emoji       = '🔥';
  prioridad   = '🔥 CONTACTAR YA — menos de 2h';
} else if (finalScore >= 40) {
  temperatura = 'TEMPLADO';
  emoji       = '🌤️';
  prioridad   = '🌤️ CONTACTAR en 24h';
} else {
  temperatura = 'FRIO';
  emoji       = '🧊';
  prioridad   = '🧊 Seguimiento automático';
}

const waLink = finalScore >= 70 && digits ? `https://wa.me/${digits}` : '';
const fecha  = new Date().toLocaleString('es-ES', { timeZone: 'Europe/Madrid' });

// =====================================================
// EMAIL AL TALLER
// =====================================================
const emailSubject = `${emoji} Lead ${temperatura} · ${nombre} — ${vehiculo}`;

const emailBody = `
<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#0d0d0d;color:#f0f0f0;border-radius:8px;overflow:hidden">
  <div style="background:#e10600;padding:20px 28px">
    <h1 style="margin:0;font-size:1.4rem;color:#fff">${emoji} NUEVO LEAD ${temperatura}</h1>
    <p style="margin:4px 0 0;color:rgba(255,255,255,0.85);font-size:0.9rem">${SHOP_NAME} · Sistema de captación Slipstream</p>
  </div>
  <div style="padding:24px 28px">
    <table style="width:100%;border-collapse:collapse">
      <tr><td style="padding:8px 0;color:#999;width:140px">Nombre</td><td style="padding:8px 0;font-weight:bold">${nombre}</td></tr>
      <tr><td style="padding:8px 0;color:#999">Teléfono</td><td style="padding:8px 0">${telefono}${waLink ? ` · <a href="${waLink}" style="color:#e10600">Abrir WhatsApp</a>` : ''}</td></tr>
      <tr><td style="padding:8px 0;color:#999">Instagram</td><td style="padding:8px 0">${instagram || '—'}</td></tr>
      <tr><td style="padding:8px 0;color:#999">Vehículo</td><td style="padding:8px 0">${vehiculo}</td></tr>
      <tr><td style="padding:8px 0;color:#999">Servicio</td><td style="padding:8px 0">${servicio}</td></tr>
      <tr><td style="padding:8px 0;color:#999">Zona</td><td style="padding:8px 0">${pais || '—'}</td></tr>
    </table>
    <div style="margin:16px 0;padding:14px;background:#1a1a1a;border-radius:6px;border-left:3px solid #e10600">
      <p style="margin:0;color:#ccc;font-size:0.9rem">${mensaje || 'Sin mensaje.'}</p>
    </div>
    <table style="width:100%;border-collapse:collapse">
      <tr><td style="padding:8px 0;color:#999">Score</td><td style="padding:8px 0;font-size:1.1rem;font-weight:bold;color:#e10600">${finalScore}/100</td></tr>
      <tr><td style="padding:8px 0;color:#999">Temperatura</td><td style="padding:8px 0">${emoji} ${temperatura}</td></tr>
      <tr><td style="padding:8px 0;color:#999">Prioridad</td><td style="padding:8px 0">${prioridad}</td></tr>
      <tr><td style="padding:8px 0;color:#999">Fecha</td><td style="padding:8px 0">${fecha}</td></tr>
    </table>
  </div>
</div>
`;

// =====================================================
// EMAIL DE CONFIRMACIÓN AL CLIENTE
// =====================================================
const confirmSubject = `Recibimos tu solicitud, ${nombre} 🏁`;
const confirmBody = `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#0d0d0d;color:#f0f0f0;border-radius:8px;overflow:hidden"><div style="background:#e10600;padding:20px 28px"><h1 style="margin:0;font-size:1.3rem;color:#fff">Solicitud recibida ✅</h1><p style="margin:4px 0 0;color:rgba(255,255,255,0.85);font-size:0.9rem">${SHOP_NAME}</p></div><div style="padding:24px 28px"><p>Hola <strong>${nombre}</strong>,</p><p>Hemos recibido tu solicitud para tu <strong>${vehiculo}</strong>. Nuestro equipo la está revisando y te contactaremos en menos de 24 horas.</p><div style="margin:20px 0;padding:16px;background:#1a1a1a;border-radius:6px;border-left:3px solid #e10600"><p style="margin:0 0 6px;color:#999;font-size:0.8rem">RESUMEN DE TU SOLICITUD</p><p style="margin:0"><strong>${vehiculo}</strong> · ${servicio}</p></div><p style="color:#999;font-size:0.85rem">Si tienes alguna duda puedes responder a este email directamente.</p></div></div>`;

return [{
  json: {
    nombre, email, telefono, instagram, vehiculo, servicio, mensaje, taller, pais,
    score: finalScore,
    temperatura,
    emoji,
    prioridad,
    waLink,
    fecha,
    estado: 'Nuevo',
    shopEmail:    SHOP_EMAIL,
    clientEmail:  'urkosan098@gmail.com',
    confirmSubject,
    confirmBody,
    emailSubject,
    emailBody,
  }
}];
